def _fetch_historical_ngn_rates() -> list:
    """
    Return daily USD/NGN CBN official rates oldest-first.

    PRIMARY source: _HARDCODED_NGN_RATES embedded in this file — always available,
    zero latency, survives Streamlit Cloud restarts.

    SUPPLEMENT: tries to fetch recent rates (last 30 days) from ExchangeRate-API
    to fill in anything newer than the hardcoded data. If the API fails, the
    hardcoded data is used as-is — app still works perfectly.
    """
    # Start with the full hardcoded baseline, but exclude future dates
    today_str = datetime.date.today().isoformat()
    results = {k: v for k, v in _HARDCODED_NGN_RATES.items() if k <= today_str}

    # Supplement: fetch last 30 days from live API to get most recent rates
    hdrs = {"User-Agent": "Mozilla/5.0 (compatible)", "Accept": "application/json"}
    try:
        r = requests.get(
            "https://open.er-api.com/v6/latest/USD",
            timeout=10, headers=hdrs)
        if r.status_code == 200:
            ngn = r.json().get("rates", {}).get("NGN")
            if ngn and float(ngn) > 100:
                today = datetime.date.today().strftime("%Y-%m-%d")
                results[today] = float(ngn)
    except Exception:
        pass  # hardcoded data is sufficient

    return sorted(results.items())


def _seed_historical_history():
    """
    Populate session rate_history with historical CBN rates.
    Uses _HARDCODED_NGN_RATES as primary source — instant, no network, no file I/O.
    Runs once per session (guarded by history_seeded flag).
    """
    if st.session_state.get("history_seeded"):
        return

    try:
        pairs    = _fetch_historical_ngn_rates()   # instant: reads hardcoded dict
        prev     = None
        seed_data = []
        for ds, rate in pairs:
            seed_data.append(_build_seed_entry(ds, rate, prev))
            prev = rate
    except Exception as e:
        st.warning(f"⚠️ Historical seed failed: {e}. Using session data only.")
        st.session_state.history_seeded = True
        return

    if seed_data:
        existing_dates = {d.get("timestamp", "")[:10] for d in st.session_state.rate_history}
        new_pts = [e for e in seed_data if e.get("timestamp", "")[:10] not in existing_dates]
        st.session_state.rate_history = new_pts + st.session_state.rate_history
        if len(st.session_state.rate_history) > MAX_HISTORY:
            st.session_state.rate_history = st.session_state.rate_history[-MAX_HISTORY:]

    st.session_state.history_seeded = True


# ── Call on startup: inject 1200+ hardcoded CBN rates into rate_history (instant, no network) ──
_seed_historical_history()


