GEMINI_MODELS = [
    "gemini-2.5-flash",
    "gemini-2.0-flash",
    "gemini-2.0-flash-001",
    "gemini-2.0-flash-lite",
    "gemini-2.5-flash-lite",
    "gemini-flash-latest",
]

@st.cache_data(ttl=86400)  # cache 24 hours — key doesn't change
def check_gemini_key(key: str) -> tuple:
    for model in GEMINI_MODELS:
        url = f"https://generativelanguage.googleapis.com/v1beta/models/{model}:generateContent?key={key}"
        try:
            r = requests.post(url, json={
                "contents": [{"parts": [{"text": "Reply: OK"}]}],
                "generationConfig": {"maxOutputTokens": 2}
            }, timeout=12)
            if r.status_code == 200: return True, model, ""
            if r.status_code == 403: return False, "", "API key invalid or not authorised"
            if r.status_code == 429: return True, model, "Rate limited"
        except: continue
    return False, "", "No working Gemini model found"

_key_ok, _working_model, _key_err = check_gemini_key(GEMINI_KEY)
if not _key_ok:
    st.error(f"❌ Gemini key error: {_key_err}. Check aistudio.google.com")
    st.stop()

GEMINI_DAILY_CAP = 80  # hard limit: if exceeded, skip Gemini calls and use cached data

def gemini(prompt: str, system: str = "", temperature: float = 0.2, max_tokens: int = 4096) -> str:
    # ── Daily usage guard ──────────────────────────────────────────────
    today = datetime.date.today().isoformat()
    if st.session_state.get("gemini_calls_date") != today:
        st.session_state.gemini_calls_today = 0
        st.session_state.gemini_calls_date  = today
    calls_today = st.session_state.get("gemini_calls_today", 0)
    if calls_today >= GEMINI_DAILY_CAP:
        return f"❌ Daily Gemini cap ({GEMINI_DAILY_CAP} calls) reached. Resets at midnight. Using cached data."
    st.session_state.gemini_calls_today = calls_today + 1
    # ──────────────────────────────────────────────────────────────────
    parts = []
    if system:
        parts.append({"text": f"SYSTEM:\n{system}\n\n---\n\n"})
    parts.append({"text": prompt})
    payload = {
        "contents": [{"parts": parts}],
        "generationConfig": {"temperature": temperature, "maxOutputTokens": max_tokens}
    }
    errors = []
    for model in GEMINI_MODELS:
        url = f"https://generativelanguage.googleapis.com/v1beta/models/{model}:generateContent?key={GEMINI_KEY}"
        try:
            r = requests.post(url, json=payload, timeout=45)
            if r.status_code == 200:
                return r.json()["candidates"][0]["content"]["parts"][0]["text"]
            elif r.status_code == 429:
                return "❌ Rate limit hit. Wait 60s and try again."
            elif r.status_code == 403:
                return "❌ API key invalid."
            else:
                errors.append(f"{model}: HTTP {r.status_code}")
                continue
        except Exception as e:
            errors.append(f"{model}: {str(e)[:50]}")
            continue
    return f"❌ All Gemini models failed: {' | '.join(errors)}"

def _parse_json(raw: str) -> dict:
    """
    Robust JSON parser — handles markdown fences, trailing commas, placeholders,
    and TRUNCATED responses (Gemini hits max_tokens mid-key).
    """
    if not raw or raw.startswith("❌"):
        return {}
    clean = raw.strip()

    # Strip markdown fences
    if "```" in clean:
        for p in clean.split("```"):
            p = p.strip()
            if p.startswith("json"): p = p[4:].strip()
            if p.startswith("{"): clean = p; break

    # Find opening brace
    if not clean.startswith("{"):
        idx = clean.find("{")
        if idx >= 0: clean = clean[idx:]
        else: return {}

    # Find last closing brace — if absent, JSON was truncated by token limit
    last = clean.rfind("}")
    if last >= 0:
        clean = clean[:last+1]
    else:
        # Truncated: strip the dangling incomplete token, then close the object
        clean = re.sub(r',\s*"[^"]*$', '', clean)                      # dangling "key
        clean = re.sub(r',\s*"[^"]+"\s*:\s*[^,}\]]*$', '', clean)  # dangling "k":v
        clean = clean.rstrip().rstrip(',') + '}'

    # Standard parse
    try:
        return json.loads(clean)
    except Exception:
        pass

    # Repair: trailing commas + placeholder values
    try:
        fixed = re.sub(r",\s*([}\]])", r"\1", clean)
        fixed = re.sub(r':\s*<[^>]+>', ': null', fixed)
        return json.loads(fixed)
    except Exception:
        return {}


